/// Map filter type string to PipeWire builtin label
pub(super) fn pipewire_filter_label(ft: &str) -> anyhow::Result<&'static str> {
    let label = match ft {
        "peak" => "bq_peaking",
        "lowshelf" => "bq_lowshelf",
        "highshelf" => "bq_highshelf",
        "lowpass" => "bq_lowpass",
        "highpass" | "highpassvariableq" => "bq_highpass",
        "notch" => "bq_notch",
        "bandpass" => "bq_bandpass",
        "allpass" => "bq_allpass",
        other => anyhow::bail!("Unsupported PipeWire biquad filter type '{other}'"),
    };

    Ok(label)
}

/// Map short channel name to PipeWire position string
pub(super) fn pipewire_channel_position(short: &str) -> &str {
    match short {
        "L" => "FL",
        "R" => "FR",
        "C" => "FC",
        "LFE" => "LFE",
        "SL" => "SL",
        "SR" => "SR",
        "BL" => "RL",
        "BR" => "RR",
        other => other,
    }
}
